134	ngx_int_t
135	ngx_set_inherited_sockets(ngx_cycle_t *cycle)
136	{
137	    size_t                     len;
138	    ngx_uint_t                 i;
139	    ngx_listening_t           *ls;
140	    socklen_t                  olen;
141	#if (NGX_HAVE_DEFERRED_ACCEPT || NGX_HAVE_TCP_FASTOPEN)
142	    ngx_err_t                  err;
143	#endif
144	#if (NGX_HAVE_DEFERRED_ACCEPT && defined SO_ACCEPTFILTER)
145	    struct accept_filter_arg   af;
146	#endif
147	#if (NGX_HAVE_DEFERRED_ACCEPT && defined TCP_DEFER_ACCEPT)
148	    int                        timeout;
149	#endif
150	#if (NGX_HAVE_REUSEPORT)
151	    int                        reuseport;
152	#endif
153	
154	    ls = cycle->listening.elts;
155	    for (i = 0; i < cycle->listening.nelts; i++) {
156	
157	        ls[i].sockaddr = ngx_palloc(cycle->pool, sizeof(ngx_sockaddr_t));
158	        if (ls[i].sockaddr == NULL) {
159	            return NGX_ERROR;
160	        }
161	
162	        ls[i].socklen = sizeof(ngx_sockaddr_t);
163	        if (getsockname(ls[i].fd, ls[i].sockaddr, &ls[i].socklen) == -1) {
164	            ngx_log_error(NGX_LOG_CRIT, cycle->log, ngx_socket_errno,
165	                          "getsockname() of the inherited "
166	                          "socket #%d failed", ls[i].fd);
167	            ls[i].ignore = 1;
168	            continue;
169	        }
170	
171	        if (ls[i].socklen > (socklen_t) sizeof(ngx_sockaddr_t)) {
172	            ls[i].socklen = sizeof(ngx_sockaddr_t);
173	        }
174	
175	        switch (ls[i].sockaddr->sa_family) {
176	
177	#if (NGX_HAVE_INET6)
178	        case AF_INET6:
179	            ls[i].addr_text_max_len = NGX_INET6_ADDRSTRLEN;
180	            len = NGX_INET6_ADDRSTRLEN + sizeof("[]:65535") - 1;
181	            break;
182	#endif
183	
184	#if (NGX_HAVE_UNIX_DOMAIN)
185	        case AF_UNIX:
186	            ls[i].addr_text_max_len = NGX_UNIX_ADDRSTRLEN;
187	            len = NGX_UNIX_ADDRSTRLEN;
188	            break;
189	#endif
190	
191	        case AF_INET:
192	            ls[i].addr_text_max_len = NGX_INET_ADDRSTRLEN;
193	            len = NGX_INET_ADDRSTRLEN + sizeof(":65535") - 1;
194	            break;
195	
196	        default:
197	            ngx_log_error(NGX_LOG_CRIT, cycle->log, ngx_socket_errno,
198	                          "the inherited socket #%d has "
199	                          "an unsupported protocol family", ls[i].fd);
200	            ls[i].ignore = 1;
201	            continue;
202	        }
203	
204	        ls[i].addr_text.data = ngx_pnalloc(cycle->pool, len);
205	        if (ls[i].addr_text.data == NULL) {
206	            return NGX_ERROR;
207	        }
208	
209	        len = ngx_sock_ntop(ls[i].sockaddr, ls[i].socklen,
210	                            ls[i].addr_text.data, len, 1);
211	        if (len == 0) {
212	            return NGX_ERROR;
213	        }
214	
215	        ls[i].addr_text.len = len;
216	
217	        ls[i].backlog = NGX_LISTEN_BACKLOG;
218	
219	        olen = sizeof(int);
220	
221	        if (getsockopt(ls[i].fd, SOL_SOCKET, SO_TYPE, (void *) &ls[i].type,
222	                       &olen)
223	            == -1)
224	        {
225	            ngx_log_error(NGX_LOG_CRIT, cycle->log, ngx_socket_errno,
226	                          "getsockopt(SO_TYPE) %V failed", &ls[i].addr_text);
227	            ls[i].ignore = 1;
228	            continue;
229	        }
230	
231	        olen = sizeof(int);
232	
233	        if (getsockopt(ls[i].fd, SOL_SOCKET, SO_RCVBUF, (void *) &ls[i].rcvbuf,
234	                       &olen)
235	            == -1)
236	        {
237	            ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_socket_errno,
238	                          "getsockopt(SO_RCVBUF) %V failed, ignored",
239	                          &ls[i].addr_text);
240	
241	            ls[i].rcvbuf = -1;
242	        }
243	
244	        olen = sizeof(int);
245	
246	        if (getsockopt(ls[i].fd, SOL_SOCKET, SO_SNDBUF, (void *) &ls[i].sndbuf,
247	                       &olen)
248	            == -1)
249	        {
250	            ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_socket_errno,
251	                          "getsockopt(SO_SNDBUF) %V failed, ignored",
252	                          &ls[i].addr_text);
253	
254	            ls[i].sndbuf = -1;
255	        }
256	
257	#if 0
258	        /* SO_SETFIB is currently a set only option */
259	
260	#if (NGX_HAVE_SETFIB)
261	
262	        olen = sizeof(int);
263	
264	        if (getsockopt(ls[i].fd, SOL_SOCKET, SO_SETFIB,
265	                       (void *) &ls[i].setfib, &olen)
266	            == -1)
267	        {
268	            ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_socket_errno,
269	                          "getsockopt(SO_SETFIB) %V failed, ignored",
270	                          &ls[i].addr_text);
271	
272	            ls[i].setfib = -1;
273	        }
274	
275	#endif
276	#endif
277	
278	#if (NGX_HAVE_REUSEPORT)
279	
280	        reuseport = 0;
281	        olen = sizeof(int);
282	
283	#ifdef SO_REUSEPORT_LB
284	
285	        if (getsockopt(ls[i].fd, SOL_SOCKET, SO_REUSEPORT_LB,
286	                       (void *) &reuseport, &olen)
287	            == -1)
288	        {
289	            ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_socket_errno,
290	                          "getsockopt(SO_REUSEPORT_LB) %V failed, ignored",
291	                          &ls[i].addr_text);
292	
293	        } else {
294	            ls[i].reuseport = reuseport ? 1 : 0;
295	        }
296	
297	#else
298	
299	        if (getsockopt(ls[i].fd, SOL_SOCKET, SO_REUSEPORT,
300	                       (void *) &reuseport, &olen)
301	            == -1)
302	        {
303	            ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_socket_errno,
304	                          "getsockopt(SO_REUSEPORT) %V failed, ignored",
305	                          &ls[i].addr_text);
306	
307	        } else {
308	            ls[i].reuseport = reuseport ? 1 : 0;
309	        }
310	#endif
311	
312	#endif
313	
314	        if (ls[i].type != SOCK_STREAM) {
315	            continue;
316	        }
317	
318	#ifdef SO_PROTOCOL
319	
320	        olen = sizeof(int);
321	
322	        if (getsockopt(ls[i].fd, SOL_SOCKET, SO_PROTOCOL,
323	                       (void *) &ls[i].protocol, &olen)
324	            == -1)
325	        {
326	            ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_socket_errno,
327	                          "getsockopt(SO_PROTOCOL) %V failed, ignored",
328	                          &ls[i].addr_text);
329	            ls[i].protocol = 0;
330	
331	        } else if (ls[i].protocol == IPPROTO_TCP) {
332	            ls[i].protocol = 0;
333	        }
334	
335	#endif
336	
337	#if (NGX_HAVE_TCP_FASTOPEN)
338	
339	        olen = sizeof(int);
340	
341	        if (getsockopt(ls[i].fd, IPPROTO_TCP, TCP_FASTOPEN,
342	                       (void *) &ls[i].fastopen, &olen)
343	            == -1)
344	        {
345	            err = ngx_socket_errno;
346	
347	            if (err != NGX_EOPNOTSUPP && err != NGX_ENOPROTOOPT
348	                && err != NGX_EINVAL)
349	            {
350	                ngx_log_error(NGX_LOG_NOTICE, cycle->log, err,
351	                              "getsockopt(TCP_FASTOPEN) %V failed, ignored",
352	                              &ls[i].addr_text);
353	            }
354	
355	            ls[i].fastopen = -1;
356	        }
357	
358	#endif
359	
360	#if (NGX_HAVE_DEFERRED_ACCEPT && defined SO_ACCEPTFILTER)
361	
362	        ngx_memzero(&af, sizeof(struct accept_filter_arg));
363	        olen = sizeof(struct accept_filter_arg);
364	
365	        if (getsockopt(ls[i].fd, SOL_SOCKET, SO_ACCEPTFILTER, &af, &olen)
366	            == -1)
367	        {
368	            err = ngx_socket_errno;
369	
370	            if (err == NGX_EINVAL) {
371	                continue;
372	            }
373	
374	            ngx_log_error(NGX_LOG_NOTICE, cycle->log, err,
375	                          "getsockopt(SO_ACCEPTFILTER) for %V failed, ignored",
376	                          &ls[i].addr_text);
377	            continue;
378	        }
379	
380	        if (olen < sizeof(struct accept_filter_arg) || af.af_name[0] == '\0') {
381	            continue;
382	        }
383	
384	        ls[i].accept_filter = ngx_palloc(cycle->pool, 16);
385	        if (ls[i].accept_filter == NULL) {
386	            return NGX_ERROR;
387	        }
388	
389	        (void) ngx_cpystrn((u_char *) ls[i].accept_filter,
390	                           (u_char *) af.af_name, 16);
391	#endif
392	
393	#if (NGX_HAVE_DEFERRED_ACCEPT && defined TCP_DEFER_ACCEPT)
394	
395	        timeout = 0;
396	        olen = sizeof(int);
397	
398	        if (getsockopt(ls[i].fd, IPPROTO_TCP, TCP_DEFER_ACCEPT, &timeout, &olen)
399	            == -1)
400	        {
401	            err = ngx_socket_errno;
402	
403	            if (err == NGX_EOPNOTSUPP) {
404	                continue;
405	            }
406	
407	            ngx_log_error(NGX_LOG_NOTICE, cycle->log, err,
408	                          "getsockopt(TCP_DEFER_ACCEPT) for %V failed, ignored",
409	                          &ls[i].addr_text);
410	            continue;
411	        }
412	
413	        if (olen < sizeof(int) || timeout == 0) {
414	            continue;
415	        }
416	
417	        ls[i].deferred_accept = 1;
418	#endif
419	    }
420	
421	    return NGX_OK;
422	}
