424	
425	ngx_int_t
426	ngx_open_listening_sockets(ngx_cycle_t *cycle)
427	{
428	    int               reuseaddr;
429	    ngx_uint_t        i, tries, failed;
430	    ngx_err_t         err;
431	    ngx_log_t        *log;
432	    ngx_socket_t      s;
433	    ngx_listening_t  *ls;
434	
435	    reuseaddr = 1;
436	#if (NGX_SUPPRESS_WARN)
437	    failed = 0;
438	#endif
439	
440	    log = cycle->log;
441	
442	    /* TODO: configurable try number */
443	
444	    for (tries = 5; tries; tries--) {
445	        failed = 0;
446	
447	        /* for each listening socket */
448	
449	        ls = cycle->listening.elts;
450	        for (i = 0; i < cycle->listening.nelts; i++) {
451	
452	            if (ls[i].ignore) {
453	                continue;
454	            }
455	
456	#if (NGX_HAVE_REUSEPORT)
457	
458	            if (ls[i].add_reuseport || ls[i].change_protocol) {
459	
460	                /*
461	                 * to allow transition from a socket without SO_REUSEPORT
462	                 * to multiple sockets with SO_REUSEPORT, we have to set
463	                 * SO_REUSEPORT on the old socket before opening new ones
464	                 *
465	                 * to allow transition between different socket protocols
466	                 * (e.g. IPPROTO_MPTCP), SO_REUSEPORT is set on both old
467	                 * and new sockets
468	                 */
469	
470	                int  reuseport = 1;
471	
472	#ifdef SO_REUSEPORT_LB
473	
474	                if (setsockopt(ls[i].fd, SOL_SOCKET, SO_REUSEPORT_LB,
475	                               (const void *) &reuseport, sizeof(int))
476	                    == -1)
477	                {
478	                    ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_socket_errno,
479	                                  "setsockopt(SO_REUSEPORT_LB) %V failed, "
480	                                  "ignored",
481	                                  &ls[i].addr_text);
482	                }
483	
484	#else
485	
486	                if (setsockopt(ls[i].fd, SOL_SOCKET, SO_REUSEPORT,
487	                               (const void *) &reuseport, sizeof(int))
488	                    == -1)
489	                {
490	                    ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_socket_errno,
491	                                  "setsockopt(SO_REUSEPORT) %V failed, ignored",
492	                                  &ls[i].addr_text);
493	                }
494	#endif
495	
496	                ls[i].add_reuseport = 0;
497	            }
498	#endif
499	
500	            if (ls[i].fd != (ngx_socket_t) -1 && !ls[i].change_protocol) {
501	                continue;
502	            }
503	
504	            if (ls[i].inherited) {
505	
506	                /* TODO: close on exit */
507	                /* TODO: nonblocking */
508	                /* TODO: deferred accept */
509	
510	                continue;
511	            }
512	
513	            s = ngx_socket(ls[i].sockaddr->sa_family, ls[i].type,
514	                           ls[i].protocol);
515	
516	            if (s == (ngx_socket_t) -1) {
517	                ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
518	                              ngx_socket_n " %V failed", &ls[i].addr_text);
519	                return NGX_ERROR;
520	            }
521	
522	            if (ls[i].type != SOCK_DGRAM || !ngx_test_config) {
523	
524	                if (setsockopt(s, SOL_SOCKET, SO_REUSEADDR,
525	                               (const void *) &reuseaddr, sizeof(int))
526	                    == -1)
527	                {
528	                    ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
529	                                  "setsockopt(SO_REUSEADDR) %V failed",
530	                                  &ls[i].addr_text);
531	
532	                    if (ngx_close_socket(s) == -1) {
533	                        ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
534	                                      ngx_close_socket_n " %V failed",
535	                                      &ls[i].addr_text);
536	                    }
537	
538	                    return NGX_ERROR;
539	                }
540	            }
541	
542	#if (NGX_HAVE_REUSEPORT)
543	
544	            if ((ls[i].reuseport || ls[i].change_protocol)
545	                && !ngx_test_config)
546	            {
547	                int  reuseport;
548	
549	                reuseport = 1;
550	
551	#ifdef SO_REUSEPORT_LB
552	
553	                if (setsockopt(s, SOL_SOCKET, SO_REUSEPORT_LB,
554	                               (const void *) &reuseport, sizeof(int))
555	                    == -1)
556	                {
557	                    ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
558	                                  "setsockopt(SO_REUSEPORT_LB) %V failed",
559	                                  &ls[i].addr_text);
560	
561	                    if (ngx_close_socket(s) == -1) {
562	                        ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
563	                                      ngx_close_socket_n " %V failed",
564	                                      &ls[i].addr_text);
565	                    }
566	
567	                    return NGX_ERROR;
568	                }
569	
570	#else
571	
572	                if (setsockopt(s, SOL_SOCKET, SO_REUSEPORT,
573	                               (const void *) &reuseport, sizeof(int))
574	                    == -1)
575	                {
576	                    ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
577	                                  "setsockopt(SO_REUSEPORT) %V failed",
578	                                  &ls[i].addr_text);
579	
580	                    if (ngx_close_socket(s) == -1) {
581	                        ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
582	                                      ngx_close_socket_n " %V failed",
583	                                      &ls[i].addr_text);
584	                    }
585	
586	                    return NGX_ERROR;
587	                }
588	#endif
589	            }
590	#endif
591	
592	#if (NGX_HAVE_INET6 && defined IPV6_V6ONLY)
593	
594	            if (ls[i].sockaddr->sa_family == AF_INET6) {
595	                int  ipv6only;
596	
597	                ipv6only = ls[i].ipv6only;
598	
599	                if (setsockopt(s, IPPROTO_IPV6, IPV6_V6ONLY,
600	                               (const void *) &ipv6only, sizeof(int))
601	                    == -1)
602	                {
603	                    ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
604	                                  "setsockopt(IPV6_V6ONLY) %V failed, ignored",
605	                                  &ls[i].addr_text);
606	                }
607	            }
608	#endif
609	            /* TODO: close on exit */
610	
611	            if (!(ngx_event_flags & NGX_USE_IOCP_EVENT)) {
612	                if (ngx_nonblocking(s) == -1) {
613	                    ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
614	                                  ngx_nonblocking_n " %V failed",
615	                                  &ls[i].addr_text);
616	
617	                    if (ngx_close_socket(s) == -1) {
618	                        ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
619	                                      ngx_close_socket_n " %V failed",
620	                                      &ls[i].addr_text);
621	                    }
622	
623	                    return NGX_ERROR;
624	                }
625	            }
626	
627	            ngx_log_debug2(NGX_LOG_DEBUG_CORE, log, 0,
628	                           "bind() %V #%d ", &ls[i].addr_text, s);
629	
630	            if (bind(s, ls[i].sockaddr, ls[i].socklen) == -1) {
631	                err = ngx_socket_errno;
632	
633	                if (err != NGX_EADDRINUSE || !ngx_test_config) {
634	                    ngx_log_error(NGX_LOG_EMERG, log, err,
635	                                  "bind() to %V failed", &ls[i].addr_text);
636	                }
637	
638	                if (ngx_close_socket(s) == -1) {
639	                    ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
640	                                  ngx_close_socket_n " %V failed",
641	                                  &ls[i].addr_text);
642	                }
643	
644	                if (err != NGX_EADDRINUSE) {
645	                    return NGX_ERROR;
646	                }
647	
648	                if (!ngx_test_config) {
649	                    failed = 1;
650	                }
651	
652	                continue;
653	            }
654	
655	#if (NGX_HAVE_UNIX_DOMAIN)
656	
657	            if (ls[i].sockaddr->sa_family == AF_UNIX) {
658	                mode_t   mode;
659	                u_char  *name;
660	
661	                name = ls[i].addr_text.data + sizeof("unix:") - 1;
662	                mode = (S_IRUSR|S_IWUSR|S_IRGRP|S_IWGRP|S_IROTH|S_IWOTH);
663	
664	                if (chmod((char *) name, mode) == -1) {
665	                    ngx_log_error(NGX_LOG_EMERG, cycle->log, ngx_errno,
666	                                  "chmod() \"%s\" failed", name);
667	                }
668	
669	                if (ngx_test_config) {
670	                    if (ngx_delete_file(name) == NGX_FILE_ERROR) {
671	                        ngx_log_error(NGX_LOG_EMERG, cycle->log, ngx_errno,
672	                                      ngx_delete_file_n " %s failed", name);
673	                    }
674	                }
675	            }
676	#endif
677	
678	            if (ls[i].type != SOCK_STREAM) {
679	                ls[i].fd = s;
680	                ls[i].open = 1;
681	                continue;
682	            }
683	
684	            if (listen(s, ls[i].backlog) == -1) {
685	                err = ngx_socket_errno;
686	
687	                /*
688	                 * on OpenVZ after suspend/resume EADDRINUSE
689	                 * may be returned by listen() instead of bind(), see
690	                 * https://bugs.openvz.org/browse/OVZ-5587
691	                 */
692	
693	                if (err != NGX_EADDRINUSE || !ngx_test_config) {
694	                    ngx_log_error(NGX_LOG_EMERG, log, err,
695	                                  "listen() to %V, backlog %d failed",
696	                                  &ls[i].addr_text, ls[i].backlog);
697	                }
698	
699	                if (ngx_close_socket(s) == -1) {
700	                    ngx_log_error(NGX_LOG_EMERG, log, ngx_socket_errno,
701	                                  ngx_close_socket_n " %V failed",
702	                                  &ls[i].addr_text);
703	                }
704	
705	                if (err != NGX_EADDRINUSE) {
706	                    return NGX_ERROR;
707	                }
708	
709	                if (!ngx_test_config) {
710	                    failed = 1;
711	                }
712	
713	                continue;
714	            }
715	
716	            ls[i].listen = 1;
717	
718	            ls[i].fd = s;
719	            ls[i].open = 1;
720	        }
721	
722	        if (!failed) {
723	            break;
724	        }
725	
726	        /* TODO: delay configurable */
727	
728	        ngx_log_error(NGX_LOG_NOTICE, log, 0,
729	                      "try again to bind() after 500ms");
730	
731	        ngx_msleep(500);
732	    }
733	
734	    if (failed) {
735	        ngx_log_error(NGX_LOG_EMERG, log, 0, "still could not bind()");
736	        return NGX_ERROR;
737	    }
738	
739	    return NGX_OK;
740	}
