1100	        }
1101	
1102	#elif (NGX_HAVE_IPV6_DONTFRAG)
1103	
1104	        if (ls[i].quic && ls[i].sockaddr->sa_family == AF_INET6) {
1105	            value = 1;
1106	
1107	            if (setsockopt(ls[i].fd, IPPROTO_IPV6, IPV6_DONTFRAG,
1108	                           (const void *) &value, sizeof(int))
1109	                == -1)
1110	            {
1111	                ngx_log_error(NGX_LOG_ALERT, cycle->log, ngx_socket_errno,
1112	                              "setsockopt(IPV6_DONTFRAG) "
1113	                              "for %V failed, ignored",
1114	                              &ls[i].addr_text);
