1127	void
1128	ngx_close_listening_sockets(ngx_cycle_t *cycle)
1129	{
1130	    ngx_uint_t         i;
1131	    ngx_listening_t   *ls;
1132	    ngx_connection_t  *c;
1133	
1134	    if (ngx_event_flags & NGX_USE_IOCP_EVENT) {
1135	        return;
1136	    }
1137	
1138	    ngx_accept_mutex_held = 0;
1139	    ngx_use_accept_mutex = 0;
1140	
1141	    ls = cycle->listening.elts;
1142	    for (i = 0; i < cycle->listening.nelts; i++) {
1143	
1144	#if (NGX_QUIC)
1145	        if (ls[i].quic) {
1146	            continue;
1147	        }
1148	#endif
1149	
1150	        c = ls[i].connection;
1151	
1152	        if (c) {
1153	            if (c->read->active) {
1154	                if (ngx_event_flags & NGX_USE_EPOLL_EVENT) {
1155	
1156	                    /*
1157	                     * it seems that Linux-2.6.x OpenVZ sends events
1158	                     * for closed shared listening sockets unless
1159	                     * the events was explicitly deleted
1160	                     */
1161	
1162	                    ngx_del_event(c->read, NGX_READ_EVENT, 0);
1163	
1164	                } else {
1165	                    ngx_del_event(c->read, NGX_READ_EVENT, NGX_CLOSE_EVENT);
1166	                }
1167	            }
1168	
1169	            ngx_free_connection(c);
1170	
1171	            c->fd = (ngx_socket_t) -1;
1172	        }
1173	
1174	        ngx_log_debug2(NGX_LOG_DEBUG_CORE, cycle->log, 0,
1175	                       "close listening %V #%d ", &ls[i].addr_text, ls[i].fd);
1176	
1177	        if (ngx_close_socket(ls[i].fd) == -1) {
1178	            ngx_log_error(NGX_LOG_EMERG, cycle->log, ngx_socket_errno,
1179	                          ngx_close_socket_n " %V failed", &ls[i].addr_text);
1180	        }
1181	
1182	#if (NGX_HAVE_UNIX_DOMAIN)
1183	
1184	        if (ls[i].sockaddr->sa_family == AF_UNIX
1185	            && ngx_process <= NGX_PROCESS_MASTER
1186	            && ngx_new_binary == 0
1187	            && (!ls[i].inherited || ngx_getppid() != ngx_parent))
1188	        {
1189	            u_char *name = ls[i].addr_text.data + sizeof("unix:") - 1;
1190	
1191	            if (ngx_delete_file(name) == NGX_FILE_ERROR) {
1192	                ngx_log_error(NGX_LOG_EMERG, cycle->log, ngx_socket_errno,
1193	                              ngx_delete_file_n " %s failed", name);
1194	            }
1195	        }
1196	
1197	#endif
1198	
1199	        ls[i].fd = (ngx_socket_t) -1;
1200	    }
1201	
1202	    cycle->listening.nelts = 0;
1203	}
1204	
1205	
1206	ngx_connection_t *
1207	ngx_get_connection(ngx_socket_t s, ngx_log_t *log)
1208	{
1209	    ngx_uint_t         instance;
1210	    ngx_event_t       *rev, *wev;
1211	    ngx_connection_t  *c;
1212	
1213	    /* disable warning: Win32 SOCKET is u_int while UNIX socket is int */
1214	
1215	    if (ngx_cycle->files && (ngx_uint_t) s >= ngx_cycle->files_n) {
1216	        ngx_log_error(NGX_LOG_ALERT, log, 0,
1217	                      "the new socket has number %d, "
1218	                      "but only %ui files are available",
1219	                      s, ngx_cycle->files_n);
1220	        return NULL;
1221	    }
1222	
1223	    ngx_drain_connections((ngx_cycle_t *) ngx_cycle);
1224	
1225	    c = ngx_cycle->free_connections;
1226	
1227	    if (c == NULL) {
1228	        ngx_log_error(NGX_LOG_ALERT, log, 0,
1229	                      "%ui worker_connections are not enough",
1230	                      ngx_cycle->connection_n);
1231	
1232	        return NULL;
1233	    }
1234	
1235	    ngx_cycle->free_connections = c->data;
1236	    ngx_cycle->free_connection_n--;
1237	
1238	    if (ngx_cycle->files && ngx_cycle->files[s] == NULL) {
1239	        ngx_cycle->files[s] = c;
1240	    }
1241	
1242	    rev = c->read;
1243	    wev = c->write;
1244	
1245	    ngx_memzero(c, sizeof(ngx_connection_t));
1246	
1247	    c->read = rev;
1248	    c->write = wev;
1249	    c->fd = s;
1250	    c->log = log;
1251	
1252	    instance = rev->instance;
1253	
1254	    ngx_memzero(rev, sizeof(ngx_event_t));
1255	    ngx_memzero(wev, sizeof(ngx_event_t));
1256	
1257	    rev->instance = !instance;
1258	    wev->instance = !instance;
1259	
1260	    rev->index = NGX_INVALID_INDEX;
1261	    wev->index = NGX_INVALID_INDEX;
1262	
1263	    rev->data = c;
1264	    wev->data = c;
1265	
1266	    wev->write = 1;
1267	
1268	    return c;
1269	}
1270	
1271	
1272	void
1273	ngx_free_connection(ngx_connection_t *c)
1274	{
1275	    c->data = ngx_cycle->free_connections;
1276	    ngx_cycle->free_connections = c;
1277	    ngx_cycle->free_connection_n++;
1278	
1279	    if (ngx_cycle->files && ngx_cycle->files[c->fd] == c) {
1280	        ngx_cycle->files[c->fd] = NULL;
1281	    }
1282	}
1283	
1284	
1285	void
1286	ngx_close_connection(ngx_connection_t *c)
1287	{
1288	    ngx_err_t     err;
1289	    ngx_uint_t    log_error, level;
1290	    ngx_socket_t  fd;
1291	
1292	    if (c->fd == (ngx_socket_t) -1) {
1293	        ngx_log_error(NGX_LOG_ALERT, c->log, 0, "connection already closed");
1294	        return;
1295	    }
1296	
1297	    if (c->read->timer_set) {
1298	        ngx_del_timer(c->read);
1299	    }
1300	
1301	    if (c->write->timer_set) {
1302	        ngx_del_timer(c->write);
1303	    }
1304	
1305	    if (!c->shared) {
1306	        if (ngx_del_conn) {
1307	            ngx_del_conn(c, NGX_CLOSE_EVENT);
1308	
1309	        } else {
1310	            if (c->read->active || c->read->disabled) {
1311	                ngx_del_event(c->read, NGX_READ_EVENT, NGX_CLOSE_EVENT);
1312	            }
1313	
1314	            if (c->write->active || c->write->disabled) {
1315	                ngx_del_event(c->write, NGX_WRITE_EVENT, NGX_CLOSE_EVENT);
1316	            }
1317	        }
1318	    }
1319	
1320	    if (c->read->posted) {
1321	        ngx_delete_posted_event(c->read);
1322	    }
1323	
1324	    if (c->write->posted) {
1325	        ngx_delete_posted_event(c->write);
1326	    }
1327	
1328	    c->read->closed = 1;
1329	    c->write->closed = 1;
1330	
1331	    ngx_reusable_connection(c, 0);
1332	
1333	    log_error = c->log_error;
1334	
1335	    ngx_free_connection(c);
1336	
1337	    fd = c->fd;
1338	    c->fd = (ngx_socket_t) -1;
1339	
1340	    if (c->shared) {
1341	        return;
1342	    }
1343	
1344	    if (ngx_close_socket(fd) == -1) {
1345	
1346	        err = ngx_socket_errno;
1347	
1348	        if (err == NGX_ECONNRESET || err == NGX_ENOTCONN) {
1349	
1350	            switch (log_error) {
1351	
1352	            case NGX_ERROR_INFO:
1353	                level = NGX_LOG_INFO;
1354	                break;
1355	
1356	            case NGX_ERROR_ERR:
1357	                level = NGX_LOG_ERR;
1358	                break;
1359	
1360	            default:
1361	                level = NGX_LOG_CRIT;
1362	            }
1363	
1364	        } else {
1365	            level = NGX_LOG_CRIT;
1366	        }
1367	
1368	        ngx_log_error(level, c->log, err, ngx_close_socket_n " %d failed", fd);
1369	    }
1370	}
1371	
1372	
1373	void
1374	ngx_reusable_connection(ngx_connection_t *c, ngx_uint_t reusable)
1375	{
1376	    ngx_log_debug1(NGX_LOG_DEBUG_CORE, c->log, 0,
1377	                   "reusable connection: %ui", reusable);
1378	
1379	    if (c->reusable) {
1380	        ngx_queue_remove(&c->queue);
1381	        ngx_cycle->reusable_connections_n--;
1382	
1383	#if (NGX_STAT_STUB)
1384	        (void) ngx_atomic_fetch_add(ngx_stat_waiting, -1);
1385	#endif
1386	    }
1387	
1388	    c->reusable = reusable;
1389	
1390	    if (reusable) {
1391	        /* need cast as ngx_cycle is volatile */
1392	
1393	        ngx_queue_insert_head(
1394	            (ngx_queue_t *) &ngx_cycle->reusable_connections_queue, &c->queue);
1395	        ngx_cycle->reusable_connections_n++;
1396	
1397	#if (NGX_STAT_STUB)
1398	        (void) ngx_atomic_fetch_add(ngx_stat_waiting, 1);
1399	#endif
1400	    }
1401	}
1402	
1403	
1404	static void
1405	ngx_drain_connections(ngx_cycle_t *cycle)
1406	{
1407	    ngx_uint_t         i, n;
1408	    ngx_queue_t       *q;
1409	    ngx_connection_t  *c;
1410	
1411	    if (cycle->free_connection_n > cycle->connection_n / 16
1412	        || cycle->reusable_connections_n == 0)
1413	    {
1414	        return;
1415	    }
1416	
1417	    if (cycle->connections_reuse_time != ngx_time()) {
1418	        cycle->connections_reuse_time = ngx_time();
1419	
1420	        ngx_log_error(NGX_LOG_WARN, cycle->log, 0,
1421	                      "%ui worker_connections are not enough, "
1422	                      "reusing connections",
1423	                      cycle->connection_n);
1424	    }
1425	
1426	    c = NULL;
1427	    n = ngx_max(ngx_min(32, cycle->reusable_connections_n / 8), 1);
1428	
1429	    for (i = 0; i < n; i++) {
1430	        if (ngx_queue_empty(&cycle->reusable_connections_queue)) {
1431	            break;
1432	        }
1433	
1434	        q = ngx_queue_last(&cycle->reusable_connections_queue);
1435	        c = ngx_queue_data(q, ngx_connection_t, queue);
1436	
1437	        ngx_log_debug0(NGX_LOG_DEBUG_CORE, c->log, 0,
1438	                       "reusing connection");
1439	
1440	        c->close = 1;
1441	        c->read->handler(c->read);
1442	    }
1443	
1444	    if (cycle->free_connection_n == 0 && c && c->reusable) {
1445	
1446	        /*
1447	         * if no connections were freed, try to reuse the last
1448	         * connection again: this should free it as long as
1449	         * previous reuse moved it to lingering close
1450	         */
1451	
1452	        ngx_log_debug0(NGX_LOG_DEBUG_CORE, c->log, 0,
1453	                       "reusing connection again");
1454	
1455	        c->close = 1;
1456	        c->read->handler(c->read);
1457	    }
1458	}
1459	
1460	
1461	void
1462	ngx_close_idle_connections(ngx_cycle_t *cycle)
1463	{
1464	    ngx_uint_t         i;
1465	    ngx_connection_t  *c;
1466	
1467	    c = cycle->connections;
1468	
1469	    for (i = 0; i < cycle->connection_n; i++) {
1470	
1471	        /* THREAD: lock */
1472	
1473	        if (c[i].fd != (ngx_socket_t) -1 && c[i].idle) {
1474	            c[i].close = 1;
1475	            c[i].read->handler(c[i].read);
1476	        }
1477	    }
1478	}
1479	
1480	
1481	ngx_int_t
1482	ngx_connection_local_sockaddr(ngx_connection_t *c, ngx_str_t *s,
1483	    ngx_uint_t port)
1484	{
1485	    socklen_t             len;
1486	    ngx_uint_t            addr;
1487	    ngx_sockaddr_t        sa;
1488	    struct sockaddr_in   *sin;
1489	#if (NGX_HAVE_INET6)
1490	    ngx_uint_t            i;
1491	    struct sockaddr_in6  *sin6;
1492	#endif
1493	
1494	    addr = 0;
1495	
1496	    if (c->local_socklen) {
1497	        switch (c->local_sockaddr->sa_family) {
1498	
1499	#if (NGX_HAVE_INET6)
1500	        case AF_INET6:
1501	            sin6 = (struct sockaddr_in6 *) c->local_sockaddr;
1502	
1503	            for (i = 0; addr == 0 && i < 16; i++) {
1504	                addr |= sin6->sin6_addr.s6_addr[i];
1505	            }
1506	
1507	            break;
1508	#endif
1509	
1510	#if (NGX_HAVE_UNIX_DOMAIN)
1511	        case AF_UNIX:
1512	            addr = 1;
1513	            break;
1514	#endif
1515	
1516	        default: /* AF_INET */
1517	            sin = (struct sockaddr_in *) c->local_sockaddr;
1518	            addr = sin->sin_addr.s_addr;
1519	            break;
1520	        }
1521	    }
1522	
1523	    if (addr == 0) {
1524	
1525	        len = sizeof(ngx_sockaddr_t);
1526	
1527	        if (getsockname(c->fd, &sa.sockaddr, &len) == -1) {
1528	            ngx_connection_error(c, ngx_socket_errno, "getsockname() failed");
1529	            return NGX_ERROR;
1530	        }
1531	
1532	        c->local_sockaddr = ngx_palloc(c->pool, len);
1533	        if (c->local_sockaddr == NULL) {
1534	            return NGX_ERROR;
1535	        }
1536	
1537	        ngx_memcpy(c->local_sockaddr, &sa, len);
1538	
1539	        c->local_socklen = len;
1540	    }
1541	
1542	    if (s == NULL) {
1543	        return NGX_OK;
1544	    }
1545	
1546	    s->len = ngx_sock_ntop(c->local_sockaddr, c->local_socklen,
1547	                           s->data, s->len, port);
1548	
1549	    return NGX_OK;
1550	}
1551	
1552	
1553	ngx_int_t
1554	ngx_tcp_nodelay(ngx_connection_t *c)
1555	{
1556	    int  tcp_nodelay;
1557	
1558	    if (c->tcp_nodelay != NGX_TCP_NODELAY_UNSET) {
1559	        return NGX_OK;
1560	    }
1561	
1562	    ngx_log_debug0(NGX_LOG_DEBUG_CORE, c->log, 0, "tcp_nodelay");
1563	
1564	    tcp_nodelay = 1;
1565	
1566	    if (setsockopt(c->fd, IPPROTO_TCP, TCP_NODELAY,
1567	                   (const void *) &tcp_nodelay, sizeof(int))
1568	        == -1)
1569	    {
1570	#if (NGX_SOLARIS)
1571	        if (c->log_error == NGX_ERROR_INFO) {
1572	
1573	            /* Solaris returns EINVAL if a socket has been shut down */
1574	            c->log_error = NGX_ERROR_IGNORE_EINVAL;
1575	
1576	            ngx_connection_error(c, ngx_socket_errno,
1577	                                 "setsockopt(TCP_NODELAY) failed");
1578	
1579	            c->log_error = NGX_ERROR_INFO;
1580	
1581	            return NGX_ERROR;
1582	        }
1583	#endif
1584	
1585	        ngx_connection_error(c, ngx_socket_errno,
1586	                             "setsockopt(TCP_NODELAY) failed");
1587	        return NGX_ERROR;
1588	    }
1589	
1590	    c->tcp_nodelay = NGX_TCP_NODELAY_SET;
1591	
1592	    return NGX_OK;
1593	}
1594	
1595	
1596	ngx_int_t
1597	ngx_connection_error(ngx_connection_t *c, ngx_err_t err, char *text)
1598	{
1599	    ngx_uint_t  level;
1600	
1601	    /* Winsock may return NGX_ECONNABORTED instead of NGX_ECONNRESET */
1602	
1603	    if ((err == NGX_ECONNRESET
1604	#if (NGX_WIN32)
1605	         || err == NGX_ECONNABORTED
1606	#endif
1607	        ) && c->log_error == NGX_ERROR_IGNORE_ECONNRESET)
1608	    {
1609	        return 0;
1610	    }
1611	
1612	#if (NGX_SOLARIS)
1613	    if (err == NGX_EINVAL && c->log_error == NGX_ERROR_IGNORE_EINVAL) {
1614	        return 0;
1615	    }
1616	#endif
1617	
1618	    if (err == NGX_EMSGSIZE && c->log_error == NGX_ERROR_IGNORE_EMSGSIZE) {
1619	        return 0;
1620	    }
1621	
1622	    if (err == 0
1623	        || err == NGX_ECONNRESET
1624	#if (NGX_WIN32)
1625	        || err == NGX_ECONNABORTED
1626	#else
1627	        || err == NGX_EPIPE
1628	#endif
1629	        || err == NGX_ENOTCONN
1630	        || err == NGX_ETIMEDOUT
1631	        || err == NGX_ECONNREFUSED
1632	        || err == NGX_ENETDOWN
1633	        || err == NGX_ENETUNREACH
1634	        || err == NGX_EHOSTDOWN
1635	        || err == NGX_EHOSTUNREACH)
1636	    {
1637	        switch (c->log_error) {
1638	
1639	        case NGX_ERROR_IGNORE_EMSGSIZE:
1640	        case NGX_ERROR_IGNORE_EINVAL:
1641	        case NGX_ERROR_IGNORE_ECONNRESET:
1642	        case NGX_ERROR_INFO:
1643	            level = NGX_LOG_INFO;
1644	            break;
1645	
1646	        default:
1647	            level = NGX_LOG_ERR;
1648	        }
1649	
1650	    } else {
1651	        level = NGX_LOG_ALERT;
1652	    }
1653	
1654	    ngx_log_error(level, c->log, err, text);
1655	
1656	    return NGX_ERROR;
1657	}
